#include<bits/stdc++.h>
using namespace std;
long long a[9][1010];
typedef long long LL;
#define gc pa==pb&&(pb=(pa=buf)+fread(buf,1,100000,stdin),pa==pb)?EOF:*pa++
static char buf[100000],*pa(buf),*pb(buf);
inline LL readint() {
	LL x=0;char c=gc;
	while(c<'0'||c>'9')c=gc;
	for(;c>='0'&&c<='9';c=gc)x=x*10+(c&15);
	return x;
}
int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        long long x=readint();
        int tot=0;
        while(x)
        {
            a[tot++][x%1000]++;
            x/=1000;
        }
    }
    long long ans=0,base=1;
    for(int i=0;i<=6;i++)
    {
        for(int j=0;j<=999;j++)
        {
            if(a[i][j]%k!=0)
            {
                ans+=base*j;
            }
        }
        base*=1000;
    }
    printf("%lld",ans);
    return 0;
}
